searchData={"items":[{"type":"module","title":"ebb_app","doc":"ebb public API","ref":"ebb_app.html"},{"type":"function","title":"ebb_app.start/2","doc":"","ref":"ebb_app.html#start/2"},{"type":"function","title":"ebb_app.stop/1","doc":"","ref":"ebb_app.html#stop/1"},{"type":"module","title":"ebb_dhcp_listener","doc":"","ref":"ebb_dhcp_listener.html"},{"type":"function","title":"ebb_dhcp_listener.code_change/3","doc":"","ref":"ebb_dhcp_listener.html#code_change/3"},{"type":"function","title":"ebb_dhcp_listener.handle_call/3","doc":"","ref":"ebb_dhcp_listener.html#handle_call/3"},{"type":"function","title":"ebb_dhcp_listener.handle_cast/2","doc":"","ref":"ebb_dhcp_listener.html#handle_cast/2"},{"type":"function","title":"ebb_dhcp_listener.handle_info/2","doc":"","ref":"ebb_dhcp_listener.html#handle_info/2"},{"type":"function","title":"ebb_dhcp_listener.init/1","doc":"","ref":"ebb_dhcp_listener.html#init/1"},{"type":"function","title":"ebb_dhcp_listener.start_link/0","doc":"","ref":"ebb_dhcp_listener.html#start_link/0"},{"type":"function","title":"ebb_dhcp_listener.terminate/2","doc":"","ref":"ebb_dhcp_listener.html#terminate/2"},{"type":"module","title":"ebb_dhcp_packet","doc":"Handles DHCP packets","ref":"ebb_dhcp_packet.html"},{"type":"type","title":"ebb_dhcp_packet.dhcp_flag/0","doc":"","ref":"ebb_dhcp_packet.html#t:dhcp_flag/0"},{"type":"type","title":"ebb_dhcp_packet.dhcp_flags/0","doc":"","ref":"ebb_dhcp_packet.html#t:dhcp_flags/0"},{"type":"type","title":"ebb_dhcp_packet.dhcp_message/0","doc":"","ref":"ebb_dhcp_packet.html#t:dhcp_message/0"},{"type":"type","title":"ebb_dhcp_packet.dhcp_option/0","doc":"","ref":"ebb_dhcp_packet.html#t:dhcp_option/0"},{"type":"type","title":"ebb_dhcp_packet.htype/0","doc":"","ref":"ebb_dhcp_packet.html#t:htype/0"},{"type":"type","title":"ebb_dhcp_packet.mac_address/0","doc":"","ref":"ebb_dhcp_packet.html#t:mac_address/0"},{"type":"type","title":"ebb_dhcp_packet.op/0","doc":"","ref":"ebb_dhcp_packet.html#t:op/0"},{"type":"function","title":"ebb_dhcp_packet.decode/1","doc":"Decodes a DHCP packet into a #dhcp_message{} record. Fields are deserialized\ninto Erlang types where possible. Not all sub-options are exhaustively\ndeserialized. In such cases, the binary is passed through to the consumer.","ref":"ebb_dhcp_packet.html#decode/1"},{"type":"function","title":"ebb_dhcp_packet.encode/1","doc":"Encodes a #dhcp_message{} record into a DHCP packet. Fields are serialized per\nRFC 2131, section 2: https://datatracker.ietf.org/doc/html/rfc2131#section-2","ref":"ebb_dhcp_packet.html#encode/1"},{"type":"module","title":"ebb_dhcpd","doc":"","ref":"ebb_dhcpd.html"},{"type":"function","title":"ebb_dhcpd.code_change/3","doc":"","ref":"ebb_dhcpd.html#code_change/3"},{"type":"function","title":"ebb_dhcpd.handle_call/3","doc":"","ref":"ebb_dhcpd.html#handle_call/3"},{"type":"function","title":"ebb_dhcpd.handle_cast/2","doc":"","ref":"ebb_dhcpd.html#handle_cast/2"},{"type":"function","title":"ebb_dhcpd.handle_info/2","doc":"","ref":"ebb_dhcpd.html#handle_info/2"},{"type":"function","title":"ebb_dhcpd.handle_request/3","doc":"","ref":"ebb_dhcpd.html#handle_request/3"},{"type":"function","title":"ebb_dhcpd.init/1","doc":"","ref":"ebb_dhcpd.html#init/1"},{"type":"function","title":"ebb_dhcpd.start_link/0","doc":"A simple stub DHCP server. This module deliberately eschews RFC 2131, RFC 2132,\nRFC 8415 and the rest of the DHCPd ecosystem. We instead focus on the minimum\ncompatible subset of DHCP needed to reliably PXE boot Linux and FreeBSD\nservers.","ref":"ebb_dhcpd.html#start_link/0"},{"type":"function","title":"ebb_dhcpd.terminate/2","doc":"","ref":"ebb_dhcpd.html#terminate/2"},{"type":"module","title":"ebb_sup","doc":"ebb top level supervisor.","ref":"ebb_sup.html"},{"type":"function","title":"ebb_sup.init/1","doc":"","ref":"ebb_sup.html#init/1"},{"type":"function","title":"ebb_sup.start_link/0","doc":"","ref":"ebb_sup.html#start_link/0"}],"proglang":"erlang","content_type":"text/markdown","producer":{"name":"ex_doc","version":"0.39.1"}}